const raw = $input.first().json.callback_query.data.replace(/^=/, '');
if (!raw.startsWith('auto_')) return [];
const parts = raw.split('_');
return [{
  json: {
    analysis_type: 'auto',
    session_id: parseInt(parts[1]),
    chat_id: $input.first().json.callback_query.message.chat.id,
    telegram_id: $input.first().json.callback_query.from.id,
    message_id: $input.first().json.callback_query.message.message_id
  }
}];

const row = $input.first().json;
const callbackData = $('Extract Callback Data').first().json;

let extractedData = {};
try {
  const raw = row.extracted_data_raw || '{}';
  extractedData = typeof raw === 'object' ? raw : JSON.parse(raw);
} catch(e) {
  extractedData = { content_type: 'document', text: '' };
}

const lang = row.language || 'FR';
const fileName = row.file_name || 'fichier';
const fileType = row.file_type || 'unknown';
const contentType = extractedData.content_type || 'document';

let userPrompt = '';

if (contentType === 'data') {
  const dataStr = JSON.stringify({
    columns: extractedData.columns || [],
    sample_data: (extractedData.data || []).slice(0, 50),
    total_rows: extractedData.total_rows || 0
  });
  userPrompt = 'Analyse ce dataset et produis un rapport complet.\n\nDONNEES :\n' + dataStr + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Francais' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown) :\n{\n  "executive_summary": "3-4 phrases",\n  "overview": {"rows": N, "columns": N, "data_quality": "X/10"},\n  "key_findings": ["finding 1", "finding 2", "finding 3"],\n  "detections": {"trends": [], "anomalies": [], "correlations": []},\n  "charts": [{"type": "bar", "title": "titre", "x": "col_x", "y": "col_y", "insight": "explication"}],\n  "recommendations": ["reco 1", "reco 2"]\n}';
} else {
  const text = (extractedData.text || '').substring(0, 8000);
  userPrompt = 'Analyse ce document et produis un rapport structure.\n\nDOCUMENT :\n' + text + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Francais' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown) :\n{\n  "executive_summary": "3-4 phrases",\n  "key_points": ["point 1", "point 2", "point 3"],\n  "insights": ["insight 1", "insight 2"],\n  "document_type": "type detecte",\n  "target_audience": "public cible",\n  "quality_score": "X/10",\n  "recommendations": ["reco 1"]\n}';
}

return [{
  json: {
    session_id: row.id || callbackData.session_id,
    chat_id: row.chat_id || callbackData.chat_id,
    telegram_id: row.telegram_id || callbackData.telegram_id,
    language: lang,
    file_name: fileName,
    file_type: fileType,
    content_type: contentType,
    extracted_data: extractedData,
    user_prompt: userPrompt,
    start_time: Date.now()
  }
}];

