const grokResponse = $input.first().json;
const metadata = $('Prepare Agent Input').first().json;

// Grok retourne choices[0].message.content
const rawOutput = (grokResponse.choices && grokResponse.choices[0])
  ? grokResponse.choices[0].message.content
  : grokResponse.text || grokResponse.output || '';

const responseTimeMs = Date.now() - (metadata.start_time || Date.now());
const tokensUsed = grokResponse.usage ? grokResponse.usage.total_tokens : 0;

console.log('rawOutput preview:', rawOutput.substring(0, 200));

let analysis = null;
try {
  let clean = rawOutput.trim();
  if (clean.startsWith('```')) {
    clean = clean.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  }
  const jsonStart = clean.indexOf('{');
  const jsonEnd = clean.lastIndexOf('}');
  if (jsonStart !== -1 && jsonEnd !== -1) {
    clean = clean.substring(jsonStart, jsonEnd + 1);
  }
  analysis = JSON.parse(clean);
} catch(e) {
  console.log('Parse error:', e.message);
  analysis = {
    executive_summary: rawOutput.substring(0, 500) || 'Analyse non disponible',
    key_findings: ['Erreur parsing JSON — verifier le modele IA'],
    parse_error: true
  };
}

return [{
  json: {
    ...metadata,
    analysis: analysis,
    response_time_ms: responseTimeMs,
    tokens_used: tokensUsed,
    llm_used: 'grok',
    parse_success: !analysis.parse_error
  }
}];

const d = $input.first().json;
const r = d.analysis;
const isFR = d.language === 'FR';
let message = '';

if (d.content_type === 'data') {
  const header = isFR ? '📊 *RAPPORT D\'ANALYSE*' : '📊 *ANALYSIS REPORT*';
  const overview = r.overview || {};
  const findings = (r.key_findings || []).map((f, i) => (i+1) + '. ' + f).join('\n');
  const recos = (r.recommendations || []).map(rec => '• ' + rec).join('\n');
  const rowsLabel = isFR ? ' lignes · ' : ' rows · ';
  const colsLabel = isFR ? ' colonnes · Qualite : ' : ' columns · Quality: ';
  message = header
    + '\n📄 *' + d.file_name + '*\n🤖 Grok AI'
    + '\n\n📋 *' + (isFR ? "Vue d'ensemble" : 'Overview') + '*\n'
    + (overview.rows || '?') + rowsLabel
    + (overview.columns || '?') + colsLabel
    + (overview.data_quality || '?')
    + '\n\n✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*\n' + (r.executive_summary || '')
    + '\n\n🔑 *' + (isFR ? 'Points Clés' : 'Key Findings') + '*\n' + findings
    + '\n\n💡 *' + (isFR ? 'Recommandations' : 'Recommendations') + '*\n' + recos
    + '\n\n⏱ _' + d.response_time_ms + 'ms · ' + (d.tokens_used || 0) + ' tokens_';
} else {
  const header = isFR ? '📄 *ANALYSE DU DOCUMENT*' : '📄 *DOCUMENT ANALYSIS*';
  const points = (r.key_points || []).map((p, i) => (i+1) + '. ' + p).join('\n');
  const insights = (r.insights || []).map(ins => '💡 ' + ins).join('\n');
  const qualityLabel = isFR ? ' · Qualite : ' : ' · Quality: ';
  message = header
    + '\n📄 *' + d.file_name + '*\n🤖 Grok AI'
    + '\n\n✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*\n' + (r.executive_summary || '')
    + '\n\n🔑 *' + (isFR ? 'Points Clés' : 'Key Points') + '*\n' + points
    + '\n\n🔍 *Insights*\n' + insights
    + '\n\n🎯 *' + (isFR ? 'Public Cible' : 'Target Audience') + '*\n'
    + (r.target_audience || (isFR ? 'Non déterminé' : 'Not determined'))
    + qualityLabel + (r.quality_score || '?')
    + '\n\n⏱ _' + d.response_time_ms + 'ms_';
}

if (message.length > 4096) message = message.substring(0, 4090) + '..._';

return [{
  json: {
    ...d,
    report_message: message,
    charts: r.charts || []
  }
}];

const d = $input.first().json;
const charts = d.charts || [];
const extractedData = d.extracted_data;

if (d.content_type !== 'data' || !charts.length || !extractedData || !extractedData.data) {
  return [{ json: { ...d, chart_urls: [], charts_count: 0 } }];
}

const rows = extractedData.data || [];
const cols = extractedData.columns || [];
const chartUrls = [];

for (const chart of charts.slice(0, 3)) {
  const type = chart.type || 'bar';
  const xCol = chart.x || cols[0];
  const yCol = chart.y || cols[1];
  if (!xCol || !yCol) continue;
  const xValues = rows.map(r => r[xCol]).filter(v => v != null).slice(0, 20);
  const yValues = rows.map(r => parseFloat(r[yCol])).filter(v => !isNaN(v)).slice(0, 20);
  if (!xValues.length || !yValues.length) continue;
  const chartConfig = {
    type: type,
    data: {
      labels: type !== 'scatter' ? xValues.map(String) : undefined,
      datasets: [{
        label: yCol,
        data: type === 'scatter' ? xValues.map((x, i) => ({ x, y: yValues[i] })) : yValues,
        backgroundColor: 'rgba(99, 102, 241, 0.5)',
        borderColor: 'rgba(99, 102, 241, 1)',
        borderWidth: 2,
        fill: false,
        tension: 0.3
      }]
    },
    options: {
      plugins: { title: { display: true, text: chart.title || (yCol + ' par ' + xCol) } }
    }
  };
  const encodedConfig = encodeURIComponent(JSON.stringify(chartConfig));
  chartUrls.push({
    url: 'https://quickchart.io/chart?c=' + encodedConfig + '&w=700&h=400&bkg=white',
    title: chart.title || '',
    insight: chart.insight || ''
  });
}

return [{ json: { ...d, chart_urls: chartUrls, charts_count: chartUrls.length } }];

const d = $input.first().json;
const agentInput = $('Prepare Agent Input').first().json;
const sessionId = agentInput.session_id || d.session_id;
const chatId = agentInput.chat_id || d.chat_id;
const language = agentInput.language || d.language;

return [{
  json: {
    p1: d.llm_used || 'grok',
    p2: Buffer.from(JSON.stringify(d.analysis || {})).toString('base64'),
    p3: String(Math.round(d.response_time_ms || 0)),
    p4: String(sessionId),
    chat_id: chatId,
    language: language,
    session_id: sessionId
  }
}];

const d = $input.first().json;
const charts = d.chart_urls || [];
if (!charts.length) return [];
return charts.map(chart => ({
  json: {
    chat_id: d.chat_id,
    photo_url: chart.url,
    caption: '📊 ' + chart.title + '\n_' + chart.insight + '_'
  }
}));
